defaultMarkers:
{{(() => {
     const data = GetOrderTracking.data[0];
     const markers = [];

     // Pickup location
     if (data?.pickup_lat && data?.pickup_lng) {
       markers.push({
         lat: parseFloat(data.pickup_lat),
         long: parseFloat(data.pickup_lng),
         title: data.pickup_name || "Pickup Location",
         color: "green"
       });
     }

     // Dropoff location
     if (data?.dropoff_lat && data?.dropoff_lng) {
       markers.push({
         lat: parseFloat(data.dropoff_lat),
         long: parseFloat(data.dropoff_lng),
         title: data.dropoff_name || "Delivery Location",
         color: "red"
       });
     }

     // Driver location (if online)
     if (data?.driver_online && data?.driver_lat) {
       markers.push({
         lat: parseFloat(data.driver_lat),
         long: parseFloat(data.driver_lng),
         title: "Driver: " + (data.driver_name || "Driver"),
         color: "blue"
       });
     }

     return markers;
   })()}}
